import java.io.*;
public class SerialVersion {
    static class Widget implements Serializable {
        private static final long serialVersionUID = 42L;
        int value;
        Widget(int v) { value = v; }
    }
    public static void main(String[] args) throws Exception {
        Widget w = new Widget(99);
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        new ObjectOutputStream(baos).writeObject(w);
        ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(baos.toByteArray()));
        Widget w2 = (Widget) ois.readObject();
        System.out.println(w2.value);
        System.out.println(w2 == w);
        System.out.println(Widget.class.getDeclaredField("serialVersionUID").getLong(null));
    }
}
